const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: false, slowMo: 100 });
  const page = await browser.newPage();

  try {
    console.log('🌐 正在访问 Amazon.com...');
    await page.goto('https://www.amazon.com', { waitUntil: 'networkidle', timeout: 30000 });
    console.log('✅ Amazon.com 已加载，标题:', await page.title());

    // 等待搜索框加载
    console.log('🔍 正在定位搜索框...');
    await page.waitForSelector('#twotabsearchtextbox', { timeout: 10000 });

    // 输入搜索词
    console.log('📝 正在输入搜索词 "mouth tape"...');
    await page.fill('#twotabsearchtextbox', 'mouth tape');

    // 点击搜索按钮
    console.log('🔘 正在点击搜索按钮...');
    await page.click('#nav-search-submit-button');

    // 等待搜索结果加载
    console.log('⏳ 等待搜索结果加载...');
    await page.waitForSelector('[data-component-type="s-search-result"]', { timeout: 10000 });

    // 截图
    console.log('📸 正在截图...');
    await page.screenshot({ path: '/tmp/amazon-mouth-tape-search.png', fullPage: true });
    console.log('✅ 截图已保存到 /tmp/amazon-mouth-tape-search.png');

    // 显示一些搜索结果信息
    const resultsCount = await page.locator('[data-component-type="s-search-result"]').count();
    console.log(`📊 找到约 ${resultsCount} 个搜索结果`);

    // 等待几秒以便查看
    await page.waitForTimeout(3000);

  } catch (error) {
    console.error('❌ 错误:', error.message);

    // 出错时也截图
    await page.screenshot({ path: '/tmp/amazon-error.png', fullPage: true });
    console.log('📸 错误截图已保存到 /tmp/amazon-error.png');
  } finally {
    console.log('🔄 正在关闭浏览器...');
    await browser.close();
    console.log('🎉 任务完成！');
  }
})();

