const { chromium } = require('playwright');

(async () => {
  // 使用更真实的浏览器参数
  const browser = await chromium.launch({
    headless: false,
    slowMo: 200,
    args: [
      '--disable-blink-features=AutomationControlled',
      '--no-sandbox',
      '--disable-dev-shm-usage'
    ]
  });

  // 创建上下文时设置用户代理和视图
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
  });

  const page = await context.newPage();

  try {
    console.log('🌐 正在访问 Amazon.com...');

    // 使用更宽松的等待条件
    await page.goto('https://www.amazon.com', {
      waitUntil: 'domcontentloaded',
      timeout: 60000
    });

    console.log('✅ Amazon.com 已加载，标题:', await page.title());

    // 检查是否被重定向到验证页面
    const currentUrl = page.url();
    if (currentUrl.includes('robot') || currentUrl.includes('verify') || currentUrl.includes('captcha')) {
      console.warn('⚠️  可能遇到了验证页面，URL:', currentUrl);
      await page.screenshot({ path: 'amazon-captcha.png', fullPage: true });
      console.log('📸 验证页面截图已保存到 amazon-captcha.png');
    }

    // 等待搜索框加载 - 尝试多种选择器
    console.log('🔍 正在定位搜索框...');

    // 尝试常见的选择器
    const searchSelectors = [
      '#twotabsearchtextbox',
      'input[name="field-keywords"]',
      'input[type="text"][aria-label="Search"]',
      'input#search',
      '.nav-search-field input'
    ];

    let searchBox = null;
    for (const selector of searchSelectors) {
      try {
        await page.waitForSelector(selector, { timeout: 5000 });
        searchBox = selector;
        console.log(`✅ 找到搜索框使用选择器: ${selector}`);
        break;
      } catch (e) {
        // 继续尝试下一个选择器
      }
    }

    if (!searchBox) {
      // 如果没找到，截图当前页面
      await page.screenshot({ path: 'amazon-no-searchbox.png', fullPage: true });
      throw new Error('找不到搜索框，页面可能未正确加载');
    }

    // 输入搜索词
    console.log('📝 正在输入搜索词 "mouth tape"...');
    await page.fill(searchBox, 'mouth tape');

    // 点击搜索按钮 - 尝试多种选择器
    console.log('🔘 正在点击搜索按钮...');
    const searchButtonSelectors = [
      '#nav-search-submit-button',
      'input[type="submit"][value="Go"]',
      '.nav-search-submit input',
      'button[type="submit"]'
    ];

    let searchClicked = false;
    for (const selector of searchButtonSelectors) {
      try {
        await page.click(selector, { timeout: 5000 });
        searchClicked = true;
        console.log(`✅ 点击搜索按钮使用选择器: ${selector}`);
        break;
      } catch (e) {
        // 继续尝试下一个选择器
      }
    }

    if (!searchClicked) {
      // 尝试按回车键
      await page.keyboard.press('Enter');
      console.log('✅ 使用回车键进行搜索');
    }

    // 等待搜索结果加载
    console.log('⏳ 等待搜索结果加载...');
    try {
      await page.waitForSelector('[data-component-type="s-search-result"]', { timeout: 15000 });
    } catch (e) {
      // 尝试其他选择器
      await page.waitForSelector('.s-result-item', { timeout: 10000 });
    }

    // 截图
    console.log('📸 正在截图...');
    await page.screenshot({ path: 'amazon-mouth-tape-search.png', fullPage: true });
    console.log('✅ 截图已保存到 amazon-mouth-tape-search.png');

    // 显示一些搜索结果信息
    try {
      const resultsCount = await page.locator('[data-component-type="s-search-result"]').count();
      console.log(`📊 找到约 ${resultsCount} 个搜索结果`);
    } catch (e) {
      const altResults = await page.locator('.s-result-item').count();
      console.log(`📊 找到约 ${altResults} 个搜索结果 (使用备用选择器)`);
    }

    // 获取页面标题
    const pageTitle = await page.title();
    console.log(`📄 搜索结果页面标题: ${pageTitle}`);

    // 等待几秒以便查看
    console.log('⏳ 等待 5 秒以便查看结果...');
    await page.waitForTimeout(5000);

  } catch (error) {
    console.error('❌ 错误:', error.message);
    console.error('错误堆栈:', error.stack);

    // 出错时也截图
    await page.screenshot({ path: 'amazon-error-v2.png', fullPage: true });
    console.log('📸 错误截图已保存到 amazon-error-v2.png');

    // 保存当前 HTML 用于调试
    const html = await page.content();
    require('fs').writeFileSync('amazon-page.html', html);
    console.log('📄 页面 HTML 已保存到 amazon-page.html');

  } finally {
    console.log('🔄 正在关闭浏览器...');
    await browser.close();
    console.log('🎉 任务完成！');
  }
})();

